const resolveRendererEntry = () => {
  const appPath = app.getAppPath();
  const candidates = [
    { path: path.resolve(__dirname, '..', '..', 'dist-renderer', 'index.html'), source: 'relative-to-main' as const },
    { path: path.join(appPath, 'dist-renderer', 'index.html'), source: 'app-root' as const },
    { path: path.join(process.resourcesPath, 'dist-renderer', 'index.html'), source: 'resources-root' as const },
  ];

  for (const candidate of candidates) {
    if (fs.existsSync(candidate.path)) {
      return candidate;
    }
  }

  logger.error('Renderer index.html not found at expected locations', { appPath, candidates });
  return { ...candidates[0], source: 'missing' as const };
};

