async function createWindow() {
  mainWindow = new BrowserWindow({
    width: 1400,
    height: 900,
    minWidth: 1024,
    minHeight: 768,
    webPreferences: {
      preload: path.join(__dirname, 'preload.js'),
      contextIsolation: true,
      nodeIntegration: false,
      sandbox: false,
      webviewTag: true, // Enable <webview> for embedded browser to bypass X-Frame-Options
    },
    titleBarStyle: process.platform === 'darwin' ? 'hiddenInset' : 'default',
    show: false,
  });

  const window = mainWindow;
  if (!window) {
    logger.error('Failed to create main window instance');
    return;
  }

  const devServerURL = process.env.VITE_DEV_SERVER_URL ?? 'http://localhost:5173';
  const { path: rendererIndexPath, source: rendererSource } = app.isPackaged
    ? resolveRendererEntry()
    : { path: path.join(__dirname, '../../dist-renderer/index.html'), source: 'dev-build' as const };

  window.webContents.on('did-fail-load', (_event, errorCode, errorDescription, validatedURL, isMainFrame) => {
    logger.error('Renderer failed to load', { errorCode, errorDescription, validatedURL, isMainFrame, rendererIndexPath });
  });

  window.webContents.once('did-finish-load', () => {
    logger.info('Renderer finished loading successfully');
  });

  window.webContents.on('render-process-gone', (_event, details) => {
    logger.error('Renderer process terminated unexpectedly', details);
  });

  // Show window when ready
  window.once('ready-to-show', () => {
    logger.info('Main window ready to show');
    window.show();
  });

  window.on('close', (event) => {
    if (allowQuit) return;
    if (hasActiveDockerDeployments()) {
      event.preventDefault();
      window.hide();
      showDeploymentBackgroundNotice();
    }
  });

  window.on('closed', () => {
    mainWindow = null;
  });

  try {
    if (isDev) {
      logger.info('Loading renderer from dev server', devServerURL);
      await window.loadURL(devServerURL);
    } else {
      logger.info('Loading renderer from file', { rendererIndexPath, rendererSource });
      await window.loadFile(rendererIndexPath);
    }
  } catch (error) {
    logger.error('Failed to load renderer', error);
    const logFilePath = getLogFilePath();
    const fallbackHtml = `
      <html>
        <body style="font-family: sans-serif; padding: 24px;">
          <h2>ServerCompass failed to load.</h2>
          <p>Check the debug log file for details.</p>
          ${logFilePath ? `<p>Log file: ${logFilePath}</p>` : ''}
        </body>
      </html>
    `;
    await window.loadURL(`data:text/html,${encodeURIComponent(fallbackHtml)}`);
  }
}

// Auto-updater event handlers
function setupAutoUpdater() {
  // Only check for updates in production builds
  if (isDev) {
    logger.info('Auto-updater disabled in development mode');
    return;
  }

  autoUpdater.on('checking-for-update', () => {
    logger.info('Checking for updates...');
    mainWindow?.webContents.send('updater:checking-for-update');
  });

  autoUpdater.on('update-available', (info) => {
    logger.info('Update available', info);

    const skippedVersion = updatePreferences.getSkippedVersion();
    if (skippedVersion && skippedVersion === info.version) {
      logger.info('Update matches skipped version; notifying renderer but not downloading.', {
        version: info.version,
      });
      mainWindow?.webContents.send('updater:update-skipped', info);
      return;
    }

    // Validate license with Lemon Squeezy API before allowing update
    // This prevents cheating by modifying local expires_at in the database
    const validateAndNotify = async () => {
      const initialInfo = licenseService.getLicenseInfo();

      // If user has a license, validate with server to get fresh expires_at
      if (initialInfo.isLicensed && initialInfo.licenseKey && initialInfo.instanceId) {
        logger.info('Validating license with server for automatic update check');
        try {
          await licenseService.validateLicense();
          logger.info('License validated successfully with server');
        } catch (validationError) {
          // For automatic checks, allow grace period - user may be offline temporarily
          logger.warn('License validation failed during auto-update check, using cached data', validationError);
        }
      }

      // Re-fetch license info after validation (may have updated expires_at from server)
      const licenseInfo = licenseService.getLicenseInfo();

      if (!licenseInfo.canUpdate) {
        logger.info('Update available but user license does not permit updates', {
          isLicensed: licenseInfo.isLicensed,
          updatesUntil: licenseInfo.updatesUntil,
        });
        mainWindow?.webContents.send('updater:update-not-eligible', {
          version: info.version,
          isLicensed: licenseInfo.isLicensed,
          updatesUntil: licenseInfo.updatesUntil,
        });
        return;
      }

      mainWindow?.webContents.send('updater:update-available', info);
    };

    void validateAndNotify();
  });

  autoUpdater.on('update-not-available', (info) => {
    logger.info('Update not available', info);
    mainWindow?.webContents.send('updater:update-not-available', info);
  });

  autoUpdater.on('download-progress', (progress) => {
    logger.info('Download progress', {
      percent: progress.percent.toFixed(2),
      transferred: progress.transferred,
      total: progress.total,
    });
    mainWindow?.webContents.send('updater:download-progress', progress);
  });

  autoUpdater.on('update-downloaded', (info) => {
    logger.info('Update downloaded', info);
    mainWindow?.webContents.send('updater:update-downloaded', info);
  });

  autoUpdater.on('error', (error) => {
    logger.error('Auto-updater error', error);
    mainWindow?.webContents.send('updater:error', {
      message: 'Auto-updater error',
      error: error.message,
    });
  });
}

// Initialize app
app.whenReady().then(async () => {
  const logFilePath = initLogger();
  logger.info('App is ready, initializing...');
  if (logFilePath) {
    logger.info('Main process log file:', logFilePath);
  }

  // Setup application menu
  setupApplicationMenu();

  // Run database migrations
  try {
    runMigrations();
    logger.info('Database initialized successfully');
  } catch (error) {
    logger.error('Failed to initialize database:', error);
    app.quit();
    return;
  }

  // Register IPC handlers
  registerServerHandlers();
  registerAppHandlers();
  registerSSHHandlers();
  registerMetricsHandlers();
  registerCronHandlers();
  registerFileHandlers();
  registerGitHandlers();
  registerCommandLogsHandlers();
  registerSettingsHandlers();
  registerPackagesHandlers();
  registerProvisioningHandlers();
  registerDatabaseHandlers();
  registerBrowserHandlers();
  // registerAutoDeployHandlers(); // DEPRECATED: Replaced by GitHub Actions
  registerGitHubActionsHandlers();
  registerGitHubActionsDockerHandlers();
  registerLicenseHandlers();
  registerUpdaterHandlers();
  registerTerminalHandlers();
  registerTemplateHandlers();
  registerCrashReportHandlers();
  registerDockerHandlers();
  registerDockerStackHandlers();
  registerTraefikHandlers();
  registerBackupHandlers();
  registerSecurityHandlers();
  registerMonitoringHandlers();
  registerLocalDockerHandlers();
  registerSecretVaultHandlers();
  registerOneClickHandlers();
  registerTunnelHandlers();
  registerFavoritePathsHandlers();
  registerBackupS3Handlers();
  registerMigrationHandlers();
  registerLocalSSHHandlers();

  // Register system handlers with secure storage
  const secureStorage = new SecureStorageService();
  registerSystemHandlers(secureStorage);

  // Create main window first (needed for GitHub services)
  await createWindow();

  // Initialize GitHub services after window is created
  if (mainWindow) {
    githubAuthService = new GitHubAuthService();
    githubApiService = new GitHubApiService();
    deepLinkService = new DeepLinkService(mainWindow);

    // Register GitHub handlers
    registerGitHubHandlers(githubAuthService, githubApiService);

    // Register deep link protocol
    deepLinkService.registerProtocol();

    // Set main window for local docker service
    setLocalDockerMainWindow(mainWindow);

    // Initialize backup scheduler
    backupSchedulerService.setMainWindow(mainWindow);
    void backupSchedulerService.initialize();

    logger.info('GitHub services initialized');
  }

  // Periodic license verification
  setInterval(() => {
    void licenseService
      .validateLicense()
      .catch((error: Error) => logger.error('Periodic license verification failed', error));
  }, 24 * 60 * 60 * 1000); // 24 hours

  setTimeout(() => {
    void licenseService
      .validateLicense()
      .catch((error: Error) => logger.error('Initial license verification failed', error));
  }, 30_000);

  // Setup auto-updater
  setupAutoUpdater();

  // Check for updates 30 seconds after app starts (non-blocking)
  if (!isDev) {
    setTimeout(() => {
      logger.info('Initiating automatic update check');
      autoUpdater.checkForUpdates().catch((error) => {
        logger.error('Failed to check for updates', error);
      });
    }, 30_000); // 30 seconds
  }

  app.on('activate', () => {
    if (BrowserWindow.getAllWindows().length === 0) {
      void createWindow();
    } else if (mainWindow) {
      mainWindow.show();
      mainWindow.focus();
    }
  });
});

// Cleanup on quit
app.on('before-quit', async (event) => {
  if (hasActiveDockerDeployments()) {
    event.preventDefault();
    allowQuit = false;
    mainWindow?.hide();
    showDeploymentBackgroundNotice();
    return;
  }

  allowQuit = true;
  logger.info('App is quitting, cleaning up...');
  backupSchedulerService.shutdown();
  closeAllTunnels();
  sshService.disconnectAll();

  // Cleanup GitHub services
  if (githubAuthService) {
    githubAuthService.destroy();
  }
  if (deepLinkService) {
    deepLinkService.destroy();
  }

  await crashReportService.shutdown();
});

// Quit when all windows are closed (except on macOS)
app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit();
  }
});

// Handle uncaught exceptions
process.on('uncaughtException', (error) => {
  logger.error('Uncaught exception:', error);
  crashReportService.captureError(error, {
    type: 'uncaughtException',
    timestamp: new Date().toISOString(),
  });

  // Notify renderer to show crash report dialog
  if (mainWindow && !mainWindow.isDestroyed()) {
    mainWindow.webContents.send('crash-report:show-dialog');
  }
});

process.on('unhandledRejection', (reason, promise) => {
  logger.error('Unhandled rejection', { promise, reason });

  const error = reason instanceof Error ? reason : new Error(String(reason));
  crashReportService.captureError(error, {
    type: 'unhandledRejection',
    timestamp: new Date().toISOString(),
    promise: String(promise),
  });

  // Notify renderer to show crash report dialog
  if (mainWindow && !mainWindow.isDestroyed()) {
    mainWindow.webContents.send('crash-report:show-dialog');
  }
});
